SELECT  DETALLE_COMPROBANTE_CNT.ANO, EXTRACT( MONTH FROM DETALLE_COMPROBANTE_CNT.FECHA) MES, DETALLE_COMPROBANTE_CNT.TIPO_CPTE, DETALLE_COMPROBANTE_CNT.COMPROBANTE, DETALLE_COMPROBANTE_CNT.CUENTA, PLAN_CONTABLE.NOMBRE, DETALLE_COMPROBANTE_CNT.REVELACIONES FROM DETALLE_COMPROBANTE_CNT LEFT JOIN PLAN_CONTABLE ON DETALLE_COMPROBANTE_CNT.COMPANIA = PLAN_CONTABLE.COMPANIA AND DETALLE_COMPROBANTE_CNT.CUENTA  = PLAN_CONTABLE.CODIGO AND DETALLE_COMPROBANTE_CNT.ANO     = PLAN_CONTABLE.ANO   WHERE s$CONDICIONENLACE$s s$CONDICIONUSUARIO$s